sys_script_client.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
// KT - REQUEST TYPE
function onSubmit() {

	var table = 'x_153465_discovert_tasker_requests';
	var RequestSysId; 
	var modalForm;
	var formAction = g_form.getActionName();

	// STRY0088787 added if statement to check the submit is a Request submit, then doin save before continuing
	if((formAction == 'openModalRespondClarificationSP')
		|| (formAction == 'openModalRequestClarificationSP')
		|| (formAction == 'openModalRespondExtensionSP')
		|| (formAction == 'openModalRequestExtensionSP')
		|| (formAction == 'openModalRespondReassignmentSP')
		|| (formAction == 'openModalRequestReassignmentSP')
		){
		// If the form is dirty, ask the user if they would like to save the record
		if((typeof spModal != 'undefined' && g_form.serialize(true).length>0)
			|| (typeof spModal == 'undefined' && g_form.modified)){

			if(confirm(getMessage('Tasker - Modal Save Changes Message'))){
				g_form.save();
			} else{
				return false;
			}
		}
	}

	//----------------------------------------------------------------------------------------------------------
	if(formAction == 'openModalRespondClarificationSP'){
		getRequestSysId('Clarification');
		if (typeof spModal != 'undefined' ) { 
			setTimeout(function(){

				spModal.open({
				title: 'Respond Clarification Request',
				message:'',
				backdrop:'static',
				widget: 'discovertasker-formtab',
				widgetInput: {table: table, sys_id: RequestSysId, view:'responsetop'},
					size:'lg',
					buttons: []
				});

			}, 2000);
		} else {
			modalForm = new GlideModalForm('Respond Clarification Request', table);
			modalForm.addParm('sysparm_view', 'responsetop'); //Specify a form view
			modalForm.render();
			modalForm.setSysID(RequestSysId);
		}
		return false;
	}

	if(formAction == 'openModalRequestClarificationSP'){
		if (typeof spModal != 'undefined' ) {
			spModal.open({
				title: 'Request Clarification',
				message:'',
				backdrop:'static',
				widget: 'discovertasker-formtab',
				widgetInput: {table: table, sys_id: -1, view: 'requesttop', parent:g_form.getUniqueValue(), u_request_type: 'Clarification'},
					size:'lg',
					buttons: []
				});
		} else{
			modalForm = new GlideModalForm('Request Clarification', table);
			modalForm.addParm('sysparm_query','parent='+g_form.getUniqueValue() + '^u_request_type=' + 'Clarification');
			modalForm.addParm('sysparm_view', 'requesttop'); //Specify a form view
			modalForm.render();
			modalForm.setSysID(-1);
		}
		return false;

	}


	//----------------------------------------------------------------------------------------------------------
	if(formAction == 'openModalRespondExtensionSP'){
		getRequestSysId('Extension');
		if (typeof spModal != 'undefined' ) { 
			setTimeout(function(){
				spModal.open({
				title: 'Respond Extension Request',
				message:'',
				backdrop:'static',
				widget: 'discovertasker-formtab',
				widgetInput: {table: table, sys_id: RequestSysId, view:'responsetop'},
					size:'lg',
					buttons: []
				});

			}, 2000);
		} else {
			modalForm = new GlideModalForm('Respond Extension Request', table);
			modalForm.addParm('sysparm_view', 'responsetop'); //Specify a form view
			modalForm.render();
			modalForm.setSysID(RequestSysId);
		}
		return false;
	}

	if(formAction == 'openModalRequestExtensionSP'){
		if (typeof spModal != 'undefined' ) {
			spModal.open({
				title: 'Request Extension',
				message:'',
				backdrop:'static',
				widget: 'discovertasker-formtab',
				widgetInput: {table: table, sys_id: -1, view: 'requesttop', parent:g_form.getUniqueValue(), u_request_type: 'Extension'},
					size:'lg',
					buttons: []
			});
		} else{
			modalForm = new GlideModalForm('Request Extension', table);
			modalForm.addParm('sysparm_query','parent='+g_form.getUniqueValue() + '^u_request_type=' + 'Extension');
			modalForm.addParm('sysparm_view', 'requesttop'); //Specify a form view
			modalForm.render();
			modalForm.setSysID(-1);
		}
		return false;
	}

	//----------------------------------------------------------------------------------------------------------
	if(formAction == 'openModalRespondReassignmentSP'){
		getRequestSysId('Reassignment');
		if (typeof spModal != 'undefined' ) { 
			setTimeout(function(){

				spModal.open({
				title: 'Reject Reassignment',
				message:'',
				backdrop:'static',
				widget: 'discovertasker-formtab',
				widgetInput: {table: table, sys_id: RequestSysId, view:'responsetop'},
					size:'lg',
					buttons: []
				});

			}, 2000);
		} else {
			modalForm = new GlideModalForm('Reject Reassignment', table);
			modalForm.addParm('sysparm_view', 'responsetop'); //Specify a form view
			modalForm.render();
			modalForm.setSysID(RequestSysId);
		}
		return false;
	}

	if(formAction == 'openModalRequestReassignmentSP'){
		if (typeof spModal != 'undefined' ) {
			spModal.open({
				title: 'Request Reassignment',
				message:'',
				backdrop:'static',
				widget: 'discovertasker-formtab',
				widgetInput: {table: table, sys_id: -1, view: 'requesttop', parent:g_form.getUniqueValue(), u_request_type: 'Reassignment'},
					size:'lg',
					buttons: []
				});
		} else{
			modalForm = new GlideModalForm('Request Reassignment', table);
			modalForm.addParm('sysparm_query','parent='+g_form.getUniqueValue() + '^u_request_type=' + 'Reassignment');
			modalForm.addParm('sysparm_view', 'requesttop'); //Specify a form view
			modalForm.render();
			modalForm.setSysID(-1);
		}
		return false;
	}

	//-----------------------------------------------------------------------------------------------------------------	
	function getRequestSysId(SelectedRequestType){
			var ga = new GlideAjax("ClientTaskRequest");
			ga.addParam('sysparm_name', 'getRequestIdToOpen');
			ga.addParam('pTaskSysId', g_form.getUniqueValue());
			ga.addParam('pRequestType', SelectedRequestType);
			ga.addParam('pStatus', 'In Progress');

			ga.getXML(getRequestSysId, null);

			function getRequestSysId(response){
				var answer = response.responseXML.documentElement.getAttribute("answer");
				RequestSysId = answer;			
			}
	}
}
